import React from 'react';
import ReactDOM from 'react-dom';
import $ from 'jquery';
import List from './components/List.jsx';

// import axios from "axios"

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      items: []
    }

    this.handleChange = this.handleChange.bind(this);
    this.handleSubmit = this.handleSubmit.bind(this);

  }

  //  handleSubmit(e){
  //    axios.get("https://localhost:3000/items").then(result => {
  //   const finalResult = result.data;
  //   console.log(finalResult) // array of object
  // }).catch(err => {
  //   console.log("Error",err);
  // });
  //  }




  componentDidMount() {
    $.ajax({
      url: '/items',

      success: (data) => {
        this.setState({
          items: data
        })
        console.log(data);
      },
      error: (err) => {
        console.log('err', err);
      }
    });
  }

  // save(){
  //   $.ajax({
  //     url: "/items",
  //     type: 'POST',
  //     data: {Name:"Hend",FavBookc:"math",topic:"math"},
  //     contentType: 'application/json',
  //     success: function (data) {
  //       console.log('Success', data);
  //     },
  //     error: function (error) {
  //       console.error('Error', error);
  //     }
  //   });
  // }

  handleChange(event) {
    this.setState({items: event.target.value});
  }

  handleSubmit(event) {
    alert('A name here: ' + this.state.value);
    event.preventDefault();
  }


  render () {
    return (<div>
      <h1>PreferencesBooks</h1>

       <form onSubmit={this.handleSubmit}>
        <label>
          Name:
          <input type="text" value={this.state.items} onChange={this.handleChange} />
        </label><br></br><br></br><br></br>

        <label>
        favorite book:
          <input type="text" value={this.state.items} onChange={this.handleChange} />
        </label><br></br><br></br><br></br>

        <label>
         Topic:
          <input type="text" value={this.state.items} onChange={this.handleChange} />
        </label><br></br><br></br><br></br>


        <input type="submit" value="Submit" />
      </form> 
      <br></br>

      <List items={this.state.items}/>
    </div>)
  }
}

ReactDOM.render(<App />, document.getElementById('app'));
